@startuml
title netnotes

class User {
    String name
    String email
}

class Shelf {
    String name
}

class Note {
    String title
    String body
}

class Article {
    String title
    String url
}

class Tag {
    String body
}

User --> User : followes
User --> Shelf : likes
User --> Shelf : creates
User --> Note : creates
User --> Note : likes
User --> Article : finds
User --> Article : likes
User --> Tag : followes

Shelf --o Note : contains
Shelf --o Article : contains
Shelf *-- Tag : attaches

Note *-- Tag : attaches
Article *-- Tag : attaches

@enduml
